import json
import re

# Access the stored query results using the correct variable names
# The languages data should be in var_functions.query_db_54
# The README data should be in var_functions.query_db_60

# Let's check what variables are actually available
globals_dict = globals()

# Find variables that contain our data
languages_data = None
readme_data = None

for var_name, var_value in globals_dict.items():
    if 'query_db' in var_name and isinstance(var_value, list):
        if var_value and isinstance(var_value[0], dict):
            if 'repo_name' in var_value[0] and 'language_description' in var_value[0]:
                languages_data = var_value
            elif 'sample_repo_name' in var_value[0] and 'content' in var_value[0]:
                readme_data = var_value

if not languages_data or not readme_data:
    print('__RESULT__:')
    print(json.dumps({
        'error': 'Could not find required data',
        'available_vars': [k for k in globals_dict.keys() if 'query_db' in k or 'list_db' in k]
    }))
else:
    # Process the data
    readme_repos = set([record['sample_repo_name'] for record in readme_data])

    # Classify repos
    non_python_repos_with_readme = []
    python_repos = []

    for lang_record in languages_data:
        repo_name = lang_record['repo_name']
        if repo_name not in readme_repos:
            continue

        lang_desc = lang_record['language_description'].lower()
        if 'python' in lang_desc:
            python_repos.append(repo_name)
        else:
            non_python_repos_with_readme.append(repo_name)

    # Check for copyright
    copyright_repos = []
    for readme_record in readme_data:
        repo_name = readme_record['sample_repo_name']
        if repo_name in non_python_repos_with_readme:
            content = readme_record['content'] or ''
            if re.search(r'copyright|\(c\)|©|all rights reserved', content, re.IGNORECASE):
                copyright_repos.append(repo_name)

    total_non_python = len(non_python_repos_with_readme)
    copyright_count = len(copyright_repos)
    proportion = copyright_count / total_non_python if total_non_python > 0 else 0

    print('__RESULT__:')
    print(json.dumps({
        'total_repos': len(languages_data),
        'readme_repos': len(readme_repos),
        'non_python_repos': total_non_python,
        'copyright_count': copyright_count,
        'proportion': f'{proportion:.2%}'
    }))

